/* === TITLES ===
   Use for main section titles in rich text areas.
   Emphasizes hierarchy with bold weight and a contrasting underline accent. */
[selector='title'] {
  font-family: Arial, sans-serif;
  font-weight: 700;
  font-size: 1.25rem;
  /* ≈ 20px */
  line-height: 1.2;
  color: #5b6411;
  letter-spacing: 0.5px;
  border-bottom: 4px solid #cddc39;
  padding-bottom: 4px;
  margin: 10px 0;
}

/* === SUBTITLES ===
   Use for secondary headings or section dividers.
   Lighter weight than titles, with inverted color contrast for visual distinction. */
[selector='subtitle'] {
  font-family: Arial, sans-serif;
  font-weight: 500;
  font-size: 1.125rem;
  /* ≈ 18px */
  line-height: 1.2;
  color: #cddc39;
  letter-spacing: 0.5px;
  border-bottom: 3px solid #5b6411;
  padding-bottom: 3px;
  margin: 6px 0;
}

/* === TEXT (GREEN) ===
   Standard paragraph text for light backgrounds.
   Ideal for explanatory content, notes, and body text. */
[selector='text'] {
  font-family: Arial, sans-serif;
  font-weight: 600;
  font-size: 1rem;
  color: #5b6411;
  line-height: 1.4;
  margin: 5px;
  padding: 5px;
}

/* === TEXT (WHITE) ===
   Variant for text displayed over dark backgrounds.
   Maintains same font and spacing for consistent layout. */
[selector='text-white'] {
  font-family: Arial, sans-serif;
  font-weight: 600;
  font-size: 1rem;
  color: #ffffff;
  line-height: 1.4;
  margin: 5px;
  padding: 5px;
}

/* === TABLE HEADER BACKGROUND ===
   Apply to header rows or highlighted sections in table layouts. */
[selector='table-header'] {
  background-color: #5b6411;
}

[selector='table-header'] .row {
  align-items: center;
}

[selector='table-header'] [class*="col-sm-"] {
  align-items: center;
}

[selector='table-header'] p {
  margin: 0 !important;
  width: 100%;
  text-align: center;
}

[selector='table-header'] p:empty {
  display: none !important;
}

[selector='table-header'] p {
  min-height: 0 !important;
}

[selector='table-header'] .col-sm-3>div,
[selector='table-header'] .form-group,
[selector='table-header'] .form-group>div,
[selector='table-header'] .form-group>div>div {
  align-items: center;
  justify-content: center;
  width: 100%;
}

/* === TABLE ROW BACKGROUND ===
   Use for alternating rows or subtle background contrast. */
[selector='table-row'] {
  background-color: #5a641161;
}

/* === MULTI-COLUMN ALIGNMENT ===
   Utility classes for horizontal alignment in multi-column layouts. */

/* CENTER alignment */
[selector='multicolumn-centered'] {
  display: flex;
  align-items: right;
  justify-content: right;
}

/* RIGHT alignment */
[selector='multicolumn-right'] {
  display: flex;
  justify-content: flex-end;
  align-items: center;
}

/* === PAGE NAVIGATION BUTTONS ===
   Ensures consistent full-width buttons in page navigation layouts. */
[selector="page-nav"] button {
  width: 100%;
}

/* === OPTION BUTTONS ===
   Applies consistent style to grouped choice buttons or options. */
[selector='option-buttons'] button {
  text-transform: none;
  text-align: center;
  border: 1px solid #ececec;
  width: 100%;
  border-radius: 2rem;
}

/* === FORM LABELS ===
   Defines the typographic style of form field labels for clarity and uniformity. */
.form-group>label {
  font-family: Arial, sans-serif;
  font-weight: 600;
  font-size: 1rem;
  color: #5b6411;
  line-height: 1.4;
  margin: 0;
}

/* === DISPLAY HEADINGS ===
   Optional typographic scales for larger text displays or hero elements. */
.display-4 {
  font-size: 2.5rem;
}

.display-5 {
  font-size: 2rem !important;
  font-weight: 300;
}

/* === FORM GROUP SPACING ===
   Adjusts vertical spacing between grouped form fields. */
.form-group {
  margin-bottom: .8rem;
}

/* === MULTISELECT FIELD ===
   Styles the appearance of multiselect components within forms. */
.multiselect__tags {
  min-height: 46px;
  border-radius: 8px;
}

/* === INPUT FIELDS ===
   Default input field style for forms.
   Provides readable size and soft background for accessibility. */
input {
  padding: 1.4rem;
  border-radius: 8px;
  font-size: 18px;
  background-color: #ffffff;
}

/* === CHECKBOX INPUTS ===
   Sets consistent sizing and interactivity for checkbox elements. */
.form-check-input {
  height: 20px;
  width: 20px;
  border-radius: 8px;
  cursor: pointer;
  background-color: #555916 !important;
  border-color: #555916 !important;
}

/* === CHECKBOX LABELS ===
   Enhances readability and click area for associated labels. */
.form-check label {
  margin-bottom: 0;
  font-weight: 600;
  padding-left: 1rem;
  margin-top: 5px;
  cursor: pointer;
}

/* === INPUT BACKGROUND OVERRIDE ===
   Reinforces uniform background color across all input types. */
input {
  background-color: #ffffff;
}

/* HEADER */
.pmdynaform-field-title {
  border-bottom: 2px solid #D7E023;
  color: #555916;
  font-family: "Arial" !important;
  font-size: 30px;
  font-weight: 800;
  text-transform: capitalize;
  padding: 5px 10px;
}

/*DISABLED AND READONLY COLOR */
[selector='READONLY'] input.form-control:disabled,
input.form-control[readonly] {
  background-color: #dfdfdf;
  color: #333333;
  cursor: not-allowed;
}

[selector='READONLY'] .multiselect.multiselect--disabled .multiselect__tags {
  background-color: #dfdfdf;
}

[selector='READONLY'] .multiselect.multiselect--disabled .multiselect__single {
  background-color: transparent;
  color: #333333;
}


/*GRID CENTERED*/
[selector='table-center'] .col-sm-3>div,
[selector='table-center'] .form-group,
[selector='table-center'] .form-group>div,
[selector='table-center'] .form-group>div>div {
  align-items: center;
  justify-content: center;
  width: 100%;
}

/*Rich Text Validation color and style*/

[selector="CQP_VALIDATION_RICH_TEXT"] {
  background-color: #f9d2d5;
  color: #b91c1c;
  border: 1px solid #fca5a5;
  border-radius: 6px;
  padding: 10px 14px;
  font-family: Inter, Arial, sans-serif;
  font-size: 14px;
  line-height: 1.5;
}


/* CheckBox */
[selector="checkbox"]>div>div>.form-check-input {
  width: 1.2em;
  height: 1.2em;
  accent-color: #555916;
  margin-top: 0.2em;
}

[selector="checkbox"]>div>div>.form-check-label {
  margin-left: 0.25rem;
}

[selector="CENTER-ACTIONS"] {
  display: flex;
  justify-content: center;
  /* centra horizontal */
}

/***STYLE TO PERCENTAGES INPUTS**/
/* Remove number arrows */
[selector="input-percentage"] input::-webkit-outer-spin-button,
[selector="input-percentage"] input::-webkit-inner-spin-button {
  -webkit-appearance: none;
  margin: 0;
}

[selector="input-percentage"] input {
  -moz-appearance: textfield;
  padding-right: 22px;
}

/* Add % symbol */
[selector="input-percentage"] .form-group {
  position: relative;
}

[selector="input-percentage"] .form-group::after {
  content: "%";
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  color: #6c757d;
  font-size: 14px;
  pointer-events: none;
}
.inputError {
  background-color: #f38787 !important;
}

.inputOk {
  background-color: #bff3a7 !important;
}
